svg.script:
(function () {
  var svg = document.querySelector('svg');
  if (!svg || !svg.pauseAnimations) { return; }
  var DUR = 120;
  // fade-in start of every narration step, as fractions of the loop
  var STEPS = [
    0.0022, 0.0622, 0.0789, 0.0967, 0.1256, 0.1544, 0.1800,
    0.2078, 0.2411, 0.2544, 0.2689, 0.3133, 0.3411, 0.3800,
    0.4033, 0.4133, 0.4633, 0.4744,
    0.5133, 0.5267, 0.5744, 0.6022,
    0.6450, 0.6633, 0.6833, 0.7022, 0.7378, 0.7678,
    0.8022, 0.8356, 0.8522, 0.8856, 0.9189, 0.9356, 0.9578
  ].map(function (f) { return f * DUR; });
  var LAND = 0.6; // land just after the fade-in
  var playing = true;
  var mark = null; // authoritative position while paused (getCurrentTime can be stale right after setCurrentTime)

  function refreshIcon() {
    document.getElementById('ctl-icon-pause').setAttribute('display', playing ? '' : 'none');
    document.getElementById('ctl-icon-play').setAttribute('display', playing ? 'none' : '');
  }
  function pause() {
    if (playing) {
      svg.pauseAnimations();
      playing = false;
      mark = svg.getCurrentTime() % DUR;
      refreshIcon();
    }
  }
  function toggle() {
    if (playing) { pause(); }
    else { mark = null; svg.unpauseAnimations(); playing = true; refreshIcon(); }
  }
  function cur() { return (mark !== null) ? mark : svg.getCurrentTime() % DUR; }
  function jump(t) { mark = t; svg.setCurrentTime(t); }
  function next() {
    pause();
    var t = cur();
    for (var i = 0; i < STEPS.length; i++) {
      if (STEPS[i] > t + 0.25) { jump(STEPS[i] + LAND); return; }
    }
    jump(STEPS[0] + LAND);
  }
  function prev() {
    pause();
    var t = cur();
    for (var i = STEPS.length - 1; i >= 0; i--) {
      if (STEPS[i] < t - LAND - 0.4) { jump(STEPS[i] + LAND); return; }
    }
    jump(STEPS[STEPS.length - 1] + LAND);
  }

  document.getElementById('ctl-prev').addEventListener('click', prev);
  document.getElementById('ctl-toggle').addEventListener('click', toggle);
  document.getElementById('ctl-next').addEventListener('click', next);
  document.addEventListener('keydown', function (e) {
    if (e.key === ' ') { e.preventDefault(); toggle(); }
    else if (e.key === 'ArrowRight') { next(); }
    else if (e.key === 'ArrowLeft') { prev(); }
  });
  document.getElementById('ppg-controls').setAttribute('visibility', 'visible');
})();
